using namespace std;

long long solve(std::vector<std::vector<long long>> points) {
    int n = points.size();
    if (n < 4) return 0;

    long long res = 0;

    for (int i = 0; i < n; ++i) {
        map<pair<long long, long long>, int> slopeCount;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            long long dx = points[j][0] - points[i][0];
            long long dy = points[j][1] - points[i][1];
            if (dx == 0 && dy == 0) continue;

            long long g = __gcd(dx, dy);
            dx /= g;
            dy /= g;
            if (dx < 0 || (dx == 0 && dy < 0)) {
                dx = -dx;
                dy = -dy;
            }
            slopeCount[{dx, dy}]++;
        }

        for (auto& p : slopeCount) {
            int cnt = p.second;
            if (cnt >= 2) {
                res += cnt * (cnt - 1) / 2;
            }
        }
    }

    long long total = n * (n - 1) * (n - 2) * (n - 3) / 24;
    long long parallelogram = 0;

    for (int i = 0; i < n; ++i) {
        for (int j = i + 1; j < n; ++j) {
            for (int k = j + 1; k < n; ++k) {
                for (int l = k + 1; l < n; ++l) {
                    vector<pair<long long, long long>> vec = {
                        {points[i][0], points[i][1]},
                        {points[j][0], points[j][1]},
                        {points[k][0], points[k][1]},
                        {points[l][0], points[l][1]}
                    };

                    vector<pair<long long, long long>> slopes;
                    for (int a = 0; a < 4; ++a) {
                        for (int b = a + 1; b < 4; ++b) {
                            long long dx = vec[b].first - vec[a].first;
                            long long dy = vec[b].second - vec[a].second;
                            if (dx == 0 && dy == 0) continue;
                            long long g = __gcd(dx, dy);
                            dx /= g;
                            dy /= g;
                            if (dx < 0 || (dx == 0 && dy < 0)) {
                                dx = -dx;
                                dy = -dy;
                            }
                            slopes.emplace_back(dx, dy);
                        }
                    }

                    bool isTrapezoid = false;
                    for (int a = 0; a < slopes.size(); ++a) {
                        for (int b = a + 1; b < slopes.size(); ++b) {
                            if (slopes[a] == slopes[b]) {
                                isTrapezoid = true;
                                break;
                            }
                        }
                        if (isTrapezoid) break;
                    }

                    if (isTrapezoid) {
                        bool isParallelogram = false;
                        set<pair<long long, long long>> uniqueSlopes(slopes.begin(), slopes.end());
                        if (uniqueSlopes.size() == 3) {
                            isParallelogram = true;
                        }
                        if (!isParallelogram) {
                            res++;
                        } else {
                            parallelogram++;
                        }
                    }
                }
            }
        }
    }

    res += parallelogram / 3;

    return res;
