function solve(points: number[][]): number {
    const n = points.length;
    if (n < 4) return 0;

    const gcd = (a: number, b: number): number => {
        a = Math.abs(a);
        b = Math.abs(b);
        while (b) {
            const temp = b;
            b = a % b;
            a = temp;
        }
        return a;
    };

    const getSlopeKey = (dx: number, dy: number): string => {
        const g = gcd(dx, dy);
        dx /= g;
        dy /= g;
        if (dx < 0 || (dx === 0 && dy < 0)) {
            dx = -dx;
            dy = -dy;
        }
        return `${dx},${dy}`;
    };

    let trapezoidCount = 0;

    for (let i = 0; i < n; i++) {
        const slopeMap = new Map<string, number[]>();
        for (let j = 0; j < n; j++) {
            if (i === j) continue;
            const dx = points[j][0] - points[i][0];
            const dy = points[j][1] - points[i][1];
            const key = getSlopeKey(dx, dy);
            if (!slopeMap.has(key)) {
                slopeMap.set(key, []);
            }
            slopeMap.get(key)!.push(j);
        }

        for (const [_, indices] of slopeMap) {
            if (indices.length >= 2) {
                trapezoidCount += indices.length * (indices.length - 1) / 2;
            }
        }
    }

    const totalCombinations = n * (n - 1) * (n - 2) * (n - 3) / 24;
    let parallelogramCount = 0;

    for (let i = 0; i < n; i++) {
        for (let j = i + 1; j < n; j++) {
            for (let k = j + 1; k < n; k++) {
                for (let l = k + 1; l < n; l++) {
                    const selectedPoints = [
                        points[i], points[j], points[k], points[l]
                    ];
                    const slopes: string[] = [];
                    for (let a = 0; a < 4; a++) {
                        for (let b = a + 1; b < 4; b++) {
                            const dx = selectedPoints[b][0] - selectedPoints[a][0];
                            const dy = selectedPoints[b][1] - selectedPoints[a][1];
                            slopes.push(getSlopeKey(dx, dy));
                        }
                    }

                    let hasParallel = false;
                    for (let a = 0; a < slopes.length; a++) {
                        for (let b = a + 1; b < slopes.length; b++) {
                            if (slopes[a] === slopes[b]) {
                                hasParallel = true;
                                break;
                            }
                        }
                        if (hasParallel) break;
                    }

                    if (hasParallel) {
                        const uniqueSlopes = new Set(slopes);
                        if (uniqueSlopes.size === 3) {
                            parallelogramCount++;
                        } else {
                            trapezoidCount++;
                        }
                    }
                }
            }
        }
    }

    trapezoidCount += Math.floor(parallelogramCount / 3);

    return trapezoidCount;
}
